def minStartingIndex(s: str, pattern: str) -> int:
    n = len(s)
    m = len(pattern)
    dp = [[None]*(n+1) for _ in range(m+1)]
    for i in range(m+1):
        for j in range(n+1):
            if pattern[i] == s[j]:
                dp[i][j] = j
            else:
                dp[i][j] = min(dp[i-1][j], dp[i-1][j+1], dp[i][j-1], dp[i][j+1])
    return dp[m][n]

